List<RouteHub> _mergeUniqueHubs(List<RouteHub> primary, List<RouteHub> extras) {
  final Map<String, RouteHub> map = <String, RouteHub>{};
  for (final RouteHub hub in <RouteHub>[...extras, ...primary]) {
    map.putIfAbsent(hub.id, () => hub);
  }
  return map.values.toList(growable: false);
}

